private static bool TryPrompt(PageRow row, out DateOnly prompt)
{
    foreach (var w in row.Words)
        if (DateOnly.TryParseExact(w.Text, "dd/MM/yy", CultureInfo.InvariantCulture, DateTimeStyles.None, out prompt))
            return true;
    prompt = default;
    return false;
}

