public static Column ColumnAt(double left, double longX, double shortX, double netX, double promptX)
{
    if (left >= longX && left < shortX) return Column.Long;
    if (left >= shortX && left < netX) return Column.Short;
    if (left >= netX && left < promptX) return Column.Net;
    return Column.Other;
}
